{"file_path":"/project/core/common/src/Clock.kt","old_string":"/**
 * Returns a [TimeSource] that uses this [Clock] to mark a time instant and to find the amount of time elapsed since that mark.
 */
@ExperimentalTime
public fun Clock.asTimeSource(): TimeSource.WithComparableMarks = object : TimeSource.WithComparableMarks {
","new_string":"/**
 * Returns a [TimeSource] backed by this [Clock], allowing you to measure elapsed [Duration]s relative to instants
 * produced by the clock.
 *
 * This is helpful when your business logic already depends on an injectable clock but you also need monotonic
 * measurements (e.g., timeouts). The resulting [TimeSource.WithComparableMarks] keeps track of the originating clock so
 * marks from different clocks cannot be mixed accidentally.
 */
@ExperimentalTime
public fun Clock.asTimeSource(): TimeSource.WithComparableMarks = object : TimeSource.WithComparableMarks {
"}

{"file_path":"/project/core/common/src/TimeZone.kt","old_string":"/**
