","new_string":"/**
 * A time zone whose [UtcOffset] never changes.
 *
 * Fixed-offset zones are useful for interoperating with systems that transmit explicit offsets (for example, RFC 3339
 * timestamps), for storing business rules like "run at 09:00 UTC+02", or for tests where deterministic behavior across
 * daylight-saving changes is required.
 */
@Serializable(with = FixedOffsetTimeZoneSerializer::class)
public expect class FixedOffsetTimeZone : TimeZone {
"}

